def separate_paren_groups(paren_string: str) -> List[str]:
    s = paren_string.replace(" ", "")
    res = []
    start = 0
    bal = 0
    for i, ch in enumerate(s):
        if ch == "(":
            bal += 1
        elif ch == ")":
            bal -= 1
        if bal == 0 and i >= start:
            res.append(s[start:i+1])
            start = i + 1
